package utils;

import java.util.Scanner;

public class Utils {
    public static void main(String[] args) {
        // TODO code application logic here
        int edad;
        Scanner teclado = new Scanner (System.in);
        
        System.out.println("Ingrese la edad del alumno");
        edad = teclado.nextInt();
        
        if (edad >= 4 && edad <= 6){
            System.out.println("El horario del grupo KINDER");
            System.out.println("es Lunes y Miercoles de 6 a 7hrs");
        }
        else{
            if (edad >= 7 && edad <= 8){
                System.out.println("El horario del grupo de primer año");
                System.out.println("Es Martes y Jueves de 16:30hrs hasta 17:30hrs");
            }
            else{
                if (edad >= 9 && edad <= 10){
                    System.out.println("El horario del grupo de segundo año");
                    System.out.println("Es Martes y Jueves de 17:30hrs hasta 19hrs");
                }
                else{
                    if (edad >= 11 && edad <= 13){
                        System.out.println("El horario del grupo de tercer año");
                        System.out.println("Es Lunes y Miercoles de 17hrs hasta 18:30hrs");
                    }
                    else{System.out.println("Ingreso una edad que no corresponde");}
                }
            }
        }
    }
}